// ====== ADAPTADOR META CLOUD API (WhatsApp Trigger N8N) ======
const body = $input.first().json;

// Estructura Meta Cloud API
const contact = (body.contacts || [])[0] || {};
const msg = (body.messages || [])[0] || {};
const phone = (msg.from || '').replace(/\D/g, '');

// Detectar tipo y contenido
let tipo = 'texto';
let texto = '';
let tieneMedia = false;
let mediaId = null;

if (msg.type === 'text') {
  tipo = 'texto';
  texto = msg.text?.body || '';
} else if (msg.type === 'audio') {
  tipo = msg.audio?.voice ? 'voz' : 'audio';
  tieneMedia = true;
  mediaId = msg.audio?.id;
} else if (msg.type === 'image') {
  tipo = 'foto';
  texto = msg.image?.caption || '';
  tieneMedia = true;
  mediaId = msg.image?.id;
}

return [{
  json: {
    phone,
    texto,
    tipo,
    tieneMedia,
    mediaId,
    chatId: phone,
    nombre: contact.profile?.name || '',
    fromMe: false,
    rawMessage: msg
  }
}];

const response = $input.first().json;
const base64 = response.base64;
const mimetype = response.mimetype || 'image/jpeg';

return [{
  json: { success: true },
  binary: {
    data: {
      data: base64,
      mimeType: mimetype,
      fileName: 'image.jpg'
    }
  }
}];

const items = $input.all();

return [{
  json: {
    status: 'completed',
    sentCount: items.length,
    to: items[0]?.json?.to ?? null,
    messages: items.map((item) => ({
      index: item.json.messageIndex,
      message: item.json.message
    }))
  }
}];

const contenido = $('Dividir mensaje1').first().json.message.content;
const normalized = $('Normalizar mensaje1').first().json;

function limpiar(texto) {
  return texto
    ?.toString()
    .replace(/["]/g, '')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Soporte para ambos formatos: partes[] o mensaje_parte_1/2/3/4
const messages = contenido.mensajes || contenido.partes
  ? (contenido.mensajes || contenido.partes).map(limpiar).filter(Boolean)
  : [
      contenido.mensaje_parte_1,
      contenido.mensaje_parte_2,
      contenido.mensaje_parte_3,
      contenido.mensaje_parte_4,
    ].map((m) => limpiar(m)).filter(Boolean);

if (!messages.length) {
  throw new Error('No hay mensajes para enviar.');
}

return messages.map((message, index) => ({
  json: {
    to: normalized.phone,
    phoneNumberId: '1106487172540913',
    message,
    messageIndex: index + 1,
    messageCount: messages.length,
  },
}));

const prev = $input.first().json.value || '';
const nuevo = $('Normalizar mensaje1').first().json.texto;
const chatId = $('Normalizar mensaje1').first().json.chatId;
const fullMessage = prev ? prev + '\n' + nuevo : nuevo;
return [{ json: { fullMessage, chatId } }];

